import json, sys, base64, re

raw = json.load(sys.stdin)
if isinstance(raw, str): raw = json.loads(raw)
if isinstance(raw, dict) and "merged" in raw: raw = raw["merged"]
# Heym HTTP nodes often return body as a JSON-encoded string. Recursively unwrap.
def deep_parse(n, depth=0, max_depth=12):
    if depth > max_depth: return n
    if isinstance(n, str):
        s = n.strip()
        if (s.startswith('{') and s.endswith('}')) or (s.startswith('[') and s.endswith(']')):
            try:
                return deep_parse(json.loads(s), depth + 1, max_depth)
            except Exception:
                return n
        return n
    if isinstance(n, dict):
        return {k: deep_parse(v, depth + 1, max_depth) for k, v in n.items()}
    if isinstance(n, list):
        return [deep_parse(v, depth + 1, max_depth) for v in n]
    return n

raw = deep_parse(raw)
def walk(n):
    if isinstance(n, dict):
        yield n
        for v in n.values(): yield from walk(v)
    elif isinstance(n, list):
        yield n
        for v in n: yield from walk(v)

# ===== TOOL CATEGORY MAP =====
TOOL_CATEGORIES = {
    "vector_db":     ["faiss","qdrant","pinecone","weaviate","milvus","chroma","pgvector","lancedb","vespa"],
    "orm":           ["sqlalchemy","tortoise-orm","peewee","django","pony","prisma","sequelize","typeorm","mongoose","drizzle-orm"],
    "web_framework": ["fastapi","flask","django","starlette","sanic","bottle","express","koa","nestjs","hapi","fastify","next"],
    "queue":         ["celery","rq","dramatiq","arq","huey","bullmq","bull","sidekiq","kafka-python","aiokafka","pika"],
    "llm_framework": ["langchain","llama-index","haystack","dspy","semantic-kernel","autogen","crewai","guidance"],
    "http_client":   ["requests","httpx","aiohttp","urllib3","axios","node-fetch","got","superagent","ky"],
    "test":          ["pytest","unittest","nose","jest","vitest","mocha","jasmine","ava","playwright","cypress"],
    "dataframe":     ["pandas","polars","modin","dask","vaex","pyarrow"],
    "ml_training":   ["torch","tensorflow","jax","scikit-learn","xgboost","lightgbm","catboost","transformers"],
    "embeddings":    ["sentence-transformers","openai","cohere","instructor","fastembed","voyageai"],
    "cache":         ["redis","memcached","diskcache","cachetools","aiocache"],
    "validation":    ["pydantic","marshmallow","cerberus","attrs","zod","joi","yup","valibot"],
    "auth":          ["authlib","python-jose","pyjwt","passport","next-auth","jsonwebtoken","clerk-sdk-node"],
    "graph_db":      ["neo4j","py2neo","arangodb","dgraph"],
    "search":        ["elasticsearch","opensearch-py","meilisearch","typesense","algoliasearch"],
    "orchestration": ["airflow","prefect","dagster","luigi","temporalio"],
    "config":        ["hydra-core","omegaconf","dynaconf","pydantic-settings","python-decouple","dotenv"],
    "build":         ["poetry","hatch","setuptools","flit","pdm","webpack","vite","rollup","esbuild","turbo"],
}
TOOL_TO_CAT = {t: c for c, ts in TOOL_CATEGORIES.items() for t in ts}

# ===== PEP 503 canonical form (covers - _ .) =====
def canon(name):
    return re.sub(r"[-_.]+", "-", (name or "").strip().lower())

# ===== Pull control inputs =====
tool = registry = ""
eval_context = ""
for u in walk(raw):
    if not isinstance(u, dict): continue
    v_tool = (u.get("package_name") or "").strip().lower()
    v_reg  = (u.get("package_registry") or "").strip().lower()
    v_ctx  = u.get("evaluation_context") or ""
    if not tool and v_tool: tool = v_tool
    if not registry and v_reg and v_reg != "none": registry = v_reg
    if not eval_context and v_ctx: eval_context = v_ctx
tool_canon = canon(tool)

# ===== Collect base64 manifests =====
manifests = {}
readme_excerpt = ""
for u in walk(raw):
    if not isinstance(u, dict): continue
    name = (u.get("name") or "").lower()
    if u.get("content") and u.get("encoding") == "base64" and name:
        try:
            decoded = base64.b64decode(u["content"]).decode("utf-8", "replace")
        except Exception:
            continue
        if name.startswith("readme"):
            txt = re.sub(r"<[^>]+>", "", decoded)
            txt = re.sub(r"!\[[^\]]*\]\([^)]*\)", "", txt)        # images
            txt = re.sub(r"\[!\[[^\]]*\]\([^)]*\)\]\([^)]*\)", "", txt)  # badge links
            txt = re.sub(r"\n{3,}", "\n\n", txt)
            readme_excerpt = txt.strip()[:6000]
        else:
            manifests[name] = decoded

# ===== Languages (from /languages) =====
KNOWN_LANGS = {"Python","JavaScript","TypeScript","Go","Java","Rust","Ruby","C","C++","C#","Shell",
               "HTML","CSS","Jupyter Notebook","Dockerfile","Makefile","PHP","Kotlin","Swift","Scala",
               "Lua","R","Perl","Julia","Elixir","Erlang","Haskell","Vue","Svelte","SCSS","Less","TeX",
               "PowerShell","Batchfile","Markdown","YAML","TOML","JSON","HCL","Solidity"}
languages = {}
for u in walk(raw):
    if isinstance(u, dict) and u and all(isinstance(v, int) for v in u.values()):
        # /languages endpoint: capitalised string keys, at least one known language
        if all(isinstance(k, str) and k[:1].isupper() for k in u.keys()) \
           and any(k in KNOWN_LANGS for k in u.keys()):
            languages = u; break

# ===== Root contents (/contents) =====
root_dirs, root_files = [], []
for u in walk(raw):
    if isinstance(u, dict) and u.get("type") in ("dir","file") and "name" in u and "path" in u:
        if "/" not in u["path"]:
            (root_dirs if u["type"] == "dir" else root_files).append(u["name"])

# ===== Repo meta =====
repo_meta = {}
for u in walk(raw):
    if isinstance(u, dict) and "stargazers_count" in u and "full_name" in u:
        repo_meta = {
            "description": u.get("description") or "",
            "stars": u.get("stargazers_count"),
            "language_primary": u.get("language"),
            "size_kb": u.get("size"),
            "topics": u.get("topics") or [],
            "pushed_at": u.get("pushed_at"),
        }
        break

# ===== Dependency parsing =====
def norm_dep(line):
    pkg = re.split(r"[<>=!~ ;\[\(]", line.strip(), 1)[0].strip()
    return canon(pkg)

py_deps, node_deps = {}, {}
requires_python = node_engine = None

if "requirements.txt" in manifests:
    for line in manifests["requirements.txt"].splitlines():
        line = line.strip()
        if not line or line[0] in "#-": continue
        nm = norm_dep(line)
        if nm: py_deps[nm] = line

if "pyproject.toml" in manifests:
    txt = manifests["pyproject.toml"]; parsed_ok = False
    try:
        import tomllib
        data = tomllib.loads(txt)
        proj = data.get("project", {})
        requires_python = proj.get("requires-python")
        for d in proj.get("dependencies", []) or []:
            nm = norm_dep(d)
            if nm: py_deps[nm] = d
        poetry = (data.get("tool", {}) or {}).get("poetry", {})
        for k, v in (poetry.get("dependencies", {}) or {}).items():
            if k.lower() == "python": requires_python = requires_python or str(v)
            else: py_deps[canon(k)] = str(v)
        parsed_ok = True
    except Exception:
        pass
    if not parsed_ok:
        m = re.search(r'requires-python\s*=\s*["\']([^"\']+)', txt)
        if m: requires_python = m.group(1)
        block = re.search(r'\[project\.dependencies\]\s*\n(.*?)(?=\n\s*\[|\Z)', txt, re.DOTALL | re.IGNORECASE)
        if block:
            for line in block.group(1).splitlines():
                s = line.strip().strip('"').strip("'").rstrip(",")
                if s and not s.startswith("#"):
                    nm = norm_dep(s)
                    if nm: py_deps[nm] = s
        pblock = re.search(r'\[tool\.poetry\.dependencies\]\s*\n(.*?)(?=\n\s*\[|\Z)', txt, re.DOTALL | re.IGNORECASE)
        if pblock:
            for line in pblock.group(1).splitlines():
                s = line.strip()
                if "=" in s and not s.startswith("#"):
                    k, v = s.split("=", 1)
                    k = canon(k.strip().strip('"'))
                    v = v.strip().strip('"').strip("'")
                    if k and k != "python": py_deps[k] = v
                    elif k == "python": requires_python = requires_python or v

if "pipfile" in manifests:
    in_pkg = False
    for line in manifests["pipfile"].splitlines():
        s = line.strip()
        if s.lower() == "[packages]": in_pkg = True; continue
        if s.startswith("[") and in_pkg: in_pkg = False; continue
        if in_pkg and "=" in s and not s.startswith("#"):
            k = s.split("=", 1)[0].strip().strip('"')
            if k: py_deps[canon(k)] = s

if "setup.cfg" in manifests:
    in_req = False
    for line in manifests["setup.cfg"].splitlines():
        s = line.strip()
        if re.match(r"install_requires\s*=", s):
            in_req = True
            after = s.split("=", 1)[1].strip()
            if after:
                nm = norm_dep(after)
                if nm: py_deps[nm] = after
            continue
        if in_req:
            if s and not s.startswith("#") and not re.match(r"\[.*\]", s) and (line[:1] in (" ","\t") or not re.match(r"\w+\s*=", s)):
                nm = norm_dep(s)
                if nm: py_deps[nm] = s
            else:
                in_req = False

if "package.json" in manifests:
    try:
        pj = json.loads(manifests["package.json"])
        for k, v in {**pj.get("dependencies", {}), **pj.get("devDependencies", {})}.items():
            node_deps[canon(k)] = v
        node_engine = (pj.get("engines") or {}).get("node")
    except Exception:
        pass

repo_is_python = bool(py_deps) or any(k in manifests for k in ("requirements.txt","pyproject.toml","pipfile","setup.cfg"))
repo_is_node   = bool(node_deps) or "package.json" in manifests

# ===== Competitors =====
cat = TOOL_TO_CAT.get(tool_canon)
all_deps = {**py_deps, **node_deps}
existing_competitors = []
if cat:
    for sibling in TOOL_CATEGORIES[cat]:
        if canon(sibling) == tool_canon: continue
        if canon(sibling) in all_deps: existing_competitors.append(sibling)

# ===== Archetype =====
deps_set = set(all_deps.keys())
def has_any(names): return any(canon(n) in deps_set for n in names)

archetype = "unknown"
if has_any(["torch","tensorflow","jax","scikit-learn","transformers","keras"]) and (
   "notebooks" in root_dirs or any(f.endswith(".ipynb") for f in root_files)):
    archetype = "ml_research"
elif has_any(["torch","tensorflow","transformers","scikit-learn"]):
    archetype = "ml_pipeline"
elif has_any(["fastapi","flask","django","starlette","express","nestjs","koa","sanic","next"]):
    archetype = "web_service"
elif has_any(["airflow","prefect","dagster","luigi","temporalio"]):
    archetype = "data_pipeline"
elif has_any(["click","typer","argparse","commander","yargs"]) and len(deps_set) < 15:
    archetype = "cli"
elif any(d in root_dirs for d in ("terraform","helm","k8s","kustomize","ansible")):
    archetype = "infra"
elif ("setup.py" in root_files or "pyproject.toml" in manifests or "package.json" in manifests) \
     and len(deps_set) < 10 and ("src" in root_dirs or "lib" in root_dirs):
    archetype = "library"

# ===== Score =====
if registry in ("pypi","pip","python"):
    eco_ok, target_deps = repo_is_python, py_deps
elif registry == "npm":
    eco_ok, target_deps = repo_is_node, node_deps
else:
    eco_ok, target_deps = None, {}

already = tool_canon in target_deps
already_version = target_deps.get(tool_canon) if already else None
dep_count = len(target_deps)

notes, score = [], None
if not (repo_is_python or repo_is_node):
    notes.append("No dependency manifest found in target repo.")
elif eco_ok is None:
    notes.append("Tool registry unknown; cannot assess stack fit.")
elif not eco_ok:
    score = 15
    notes.append(f"Ecosystem mismatch: '{tool}' is a {registry} package but the repo is not {registry}-based.")
elif already:
    score = 92
    notes.append(f"Already declared ({already_version}) — proven to integrate.")
elif existing_competitors:
    score = 55
    notes.append(f"Competing tool(s) already in repo: {', '.join(existing_competitors)}. Adoption is a migration, not a greenfield add.")
else:
    score = 70
    notes.append(f"Ecosystem match: {registry} package against a {registry}-based repo.")

if score is not None and dep_count > 40:
    score = max(0, score - 8)
    notes.append(f"Large dep surface ({dep_count}) raises version-conflict risk.")
if requires_python and registry in ("pypi","pip","python"):
    notes.append(f"Repo targets Python {requires_python}.")
if node_engine and registry == "npm":
    notes.append(f"Repo targets Node {node_engine}.")
if score is not None: score = max(0, min(100, score))

manifests_found = [k for k in ("requirements.txt","pyproject.toml","pipfile","setup.cfg","package.json") if k in manifests]
key_libraries_detected = [d for d in all_deps.keys() if d in TOOL_TO_CAT][:25]

out = {
    "stack_compatibility": score,
    "data_available": score is not None,
    "evaluated_tool": tool,
    "registry": registry,
    "category": cat,
    "existing_competitors": existing_competitors,
    "already_dependency": already,
    "already_version": already_version,
    "declared_dependency_count": dep_count,
    "requires_python": requires_python,
    "node_engine": node_engine,
    "manifests_found": manifests_found,
    "notes": notes,
    "evaluation_context": eval_context,
    "repo_profile": {
        "archetype": archetype,
        "languages": languages,
        "language_primary": repo_meta.get("language_primary"),
        "description": repo_meta.get("description",""),
        "stars": repo_meta.get("stars"),
        "size_kb": repo_meta.get("size_kb"),
        "topics": repo_meta.get("topics", []),
        "top_level_dirs": root_dirs[:20],
        "top_level_files": [f for f in root_files if not f.startswith(".")][:20],
        "key_libraries_detected": key_libraries_detected,
    },
    "readme_excerpt": readme_excerpt,
}
print(json.dumps(out, default=str))

import json, sys

raw = json.load(sys.stdin)
if isinstance(raw, str): raw = json.loads(raw)
if isinstance(raw, dict) and "merged" in raw: raw = raw["merged"]

def walk(n):
    if isinstance(n, dict):
        yield n
        for v in n.values(): yield from walk(v)
    elif isinstance(n, list):
        for v in n: yield from walk(v)

stack = profile = None
for u in walk(raw):
    if isinstance(u, dict):
        if stack is None and "stack_compatibility" in u and "evaluated_tool" in u:
            stack = u
        if profile is None and "personal_commentary" in u and "verdict_for_this_repo" in u:
            profile = u

out = dict(stack or {})
if profile:
    out["personal_repo_commentary"] = profile
    # Lift the verdict + migration signal to top-level so downstream can read them flat
    out["repo_verdict"] = profile.get("verdict_for_this_repo")
    out["migration_effort_signal"] = profile.get("migration_effort_signal")

print(json.dumps(out, default=str))
